CREATE INDEX "auth_permission_content_type_id_2f476e4b" ON "auth_permission" ("content_type_id");
CREATE INDEX "django_session_expire_date_a5c62663" ON "django_session" ("expire_date");
CREATE INDEX "elements_contactor_fiksator_id_7bf1952a" ON "elements_contactor" ("fiksator_id");
CREATE INDEX "elements_automat_fiksator_id_9a1dd750" ON "elements_automat" ("fiksator_id");
